'use server';

import { aiWorkoutSuggester } from '@/ai/flows/ai-workout-suggester-flow';
import type { AIWorkoutSuggesterInput } from '@/ai/flows/ai-workout-suggester-flow';

export async function suggestWorkout(input: AIWorkoutSuggesterInput) {
  try {
    const result = await aiWorkoutSuggester(input);
    return { success: true, data: result };
  } catch (error) {
    console.error('AI workout suggestion failed:', error);
    return { success: false, error: (error as Error).message };
  }
}
